@app.route("/introspect", methods=["POST"])
def introspect():
    token_value = require_param("token")
    info = access_tokens.get(token_value)
    if not info:
        return jsonify(active=False)

    return jsonify(
        active=True,
        token=token_value,
        user_id=info["user_id"],
        client_id=info["client_id"],
        scope=info.get("scope", ""),
        token_type=info.get("token_type", "Bearer"),
        issued_at=info.get("issued_at", 0),
    )


@app.route("/protected", methods=["GET"])
def protected():
    auth = request.headers.get("Authorization", "")
    if not auth.startswith("Bearer "):
        return jsonify(error="invalid_request"), 401
    token_value = auth.split(" ", 1)[1].strip()
    info = access_tokens.get(token_value)
    if not info:
        return jsonify(error="invalid_token"), 401
    return jsonify(ok=True, user_id=info["user_id"], client_id=info["client_id"], scope=info.get("scope", ""))


